        // Headings (#, ##, ###)
        const hm = line.match(/^(#{1,3})\s+(.+)/);
        if (hm) {
            const level = hm[1].length;
            out.push(`<h${level}>${safeInline(hm[2].trim())}</h${level}>`);
            i++;
            continue;
        }
        // Blockquote (> o >  — recolecta líneas consecutivas)
